function loadPreferences(){try{return{...settingDefaults,...JSON.parse(localStorage.getItem('wakebound-settings-v1'))}}catch{return{...settingDefaults}}}
function savePreferences(){try{localStorage.setItem('wakebound-settings-v1',JSON.stringify(preferences))}catch{}}
function gameDelay(ms){return preferences.fastMode?Math.round(ms*.55):ms}
function schedule(fn,ms){setTimeout(()=>$('#settings-overlay')?.classList.contains('hidden')?fn():schedule(fn,100),gameDelay(ms))}
function applyPreferences(){document.body.classList.toggle('no-screen-shake',!preferences.screenShake);document.body.classList.toggle('fast-mode',preferences.fastMode);document.body.classList.toggle('reduced-effects',preferences.reducedEffects);document.querySelectorAll('.pile-count').forEach(el=>el.classList.toggle('hidden',!preferences.pileCounts));audio.refresh()}
function loadProfile(){try{const saved=JSON.parse(localStorage.getItem('wakebound-profile-v1'))||{};return{xp:Number(saved.xp)||0,seenCards:Array.isArray(saved.seenCards)?saved.seenCards:[]}}catch{return{xp:0,seenCards:[]}}}
function saveProfile(){try{localStorage.setItem('wakebound-profile-v1',JSON.stringify(state.profile))}catch{}}
function seededRandom(seed){return()=>{seed|=0;seed=seed+0x6D2B79F5|0;let t=Math.imul(seed^seed>>>15,1|seed);t=t+Math.imul(t^t>>>7,61|t)^t;return((t^t>>>14)>>>0)/4294967296}}
function makeRoute(){const seed=Math.floor(Math.random()*2147483647),random=seededRandom(seed);const route=routeLayouts.map((positions,layer)=>{const options=routeLayerOptions[layer],types=options[Math.floor(random()*options.length)].slice();if(types.length>1&&random()>.5)types.reverse();return positions.map((position,index)=>{const type=types[index],definition=routeTypes[type],name=definition.names[Math.floor(random()*definition.names.length)];return{id:`${layer}-${index}`,layer,type,name,x:position.x,y:position.y}})});return{seed,route}}
function routeNodes(){return state?.route?.reduce((all,layer)=>all.concat(layer),[])||[]}
function routeNode(id){return routeNodes().find(node=>node.id===id)||null}
function saveRun(scene=state?.scene||'map'){if(!state)return;state.scene=scene;try{localStorage.setItem(RUN_SAVE_KEY,JSON.stringify({version:RUN_SAVE_VERSION,savedAt:Date.now(),state}))}catch{}}
function loadSavedRun(){try{const saved=JSON.parse(localStorage.getItem(RUN_SAVE_KEY));if(saved?.version!==RUN_SAVE_VERSION||!Array.isArray(saved.state?.route)||saved.state.route.length!==encounters.length||saved.state.hero?.hp<=0)return null;saved.state.profile=loadProfile();saved.state.routeHistory=Array.isArray(saved.state.routeHistory)?saved.state.routeHistory:[];saved.state.scene=saved.state.scene||'map';saved.state.locked=false;return saved.state}catch{return null}}
function clearSavedRun(){try{localStorage.removeItem(RUN_SAVE_KEY)}catch{}}
function levelForXp(xp){let level=1;while(level<xpThresholds.length&&xp>=xpThresholds[level])level++;return level}
function xpProgress(){const level=levelForXp(state.profile.xp),start=xpThresholds[level-1]||0,end=xpThresholds[level]||start+150;return`${state.profile.xp-start} / ${end-start}`}
function parseCard(ref){return{base:ref.replace(/\+$/,''),upgraded:ref.endsWith('+')}}
function getCard(ref){const {base,upgraded}=parseCard(ref),original=cards[base];if(!upgraded)return original;const card={...original,name:`${original.name}+`};if(card.damage)card.damage+=3;if(card.block)card.block+=3;if(card.heal)card.heal+=1;const parts=[];if(card.damage)parts.push(`造成 ${card.damage} 点伤害。`);if(card.block)parts.push(`获得 ${card.block} 点护甲。`);if(card.heal)parts.push(`恢复 ${card.heal} 点生命。`);if(card.vulnerable)parts.push(`施加 ${card.vulnerable} 层锈蚀（攻击牌伤害 +50%）。`);if(card.energy)parts.push(`获得 ${card.energy} 点潮力。`);if(card.draw)parts.push(`抽 ${card.draw} 张牌。`);card.text=parts.join('');return card}
function cardRuleHelp(card){const keys=[];if(card.vulnerable)keys.push('rust');if(card.block)keys.push('block');if(card.energy)keys.push('energy');if(card.draw)keys.push('draw');return keys.map(key=>`${combatTerms[key].name}：${combatTerms[key].text}`).join('\n')}
function combatGlossaryMarkup(){return `<aside class="combat-glossary" aria-label="战斗词条"><p>战斗词条</p>${Object.values(combatTerms).map(term=>`<div><b>${term.name}</b><span>${term.text}</span></div>`).join('')}</aside>`}
function hasHardware(id){return state.hardware.includes(id)}
function markCardsSeen(refs){const seen=new Set(state.profile.seenCards);refs.forEach(ref=>seen.add(parseCard(ref).base));state.profile.seenCards=[...seen];saveProfile()}
function createGameAudio(){
  const tracks={
    title:{src:'assets/audio/title-buccaneers-haul.mp3',volume:.32,loop:false},
    map:{src:'assets/audio/map-eyes-ocean.mp3',volume:.32},
    battle:{src:'assets/audio/battle-pirate-indenture.mp3',volume:.31},
    elite:{src:'assets/audio/elite-kraken.mp3',volume:.3},
    boss:{src:'assets/audio/boss-determined-pursuit.mp3',volume:.3},
    reward:{src:'assets/audio/reward-inn-music.mp3',volume:.32}
  };
  let context=null,master=null,currentTrack=null,currentScene='title',started=false,muted=!preferences.audio;
  function ensure(){if(context)return context;const AudioContext=globalThis.AudioContext||globalThis.webkitAudioContext;if(!AudioContext)return null;context=new AudioContext();master=context.createGain();master.gain.value=muted?0:.42*preferences.sfxVolume/100;master.connect(context.destination);return context}
  function tone(from,to,duration,type='triangle',volume=.16,delay=0){const ctx=ensure();if(!ctx||muted)return;const now=ctx.currentTime+delay,osc=ctx.createOscillator(),gain=ctx.createGain();osc.type=type;osc.frequency.setValueAtTime(from,now);osc.frequency.exponentialRampToValueAtTime(Math.max(20,to),now+duration);gain.gain.setValueAtTime(.001,now);gain.gain.exponentialRampToValueAtTime(volume,now+.015);gain.gain.exponentialRampToValueAtTime(.001,now+duration);osc.connect(gain).connect(master);osc.start(now);osc.stop(now+duration+.03)}
  function noise(duration=.25,volume=.16,frequency=900){const ctx=ensure();if(!ctx||muted)return;const length=Math.floor(ctx.sampleRate*duration),buffer=ctx.createBuffer(1,length,ctx.sampleRate),data=buffer.getChannelData(0);for(let i=0;i<length;i++)data[i]=(Math.random()*2-1)*(1-i/length);const source=ctx.createBufferSource(),filter=ctx.createBiquadFilter(),gain=ctx.createGain();source.buffer=buffer;filter.type='lowpass';filter.frequency.value=frequency;gain.gain.value=volume;source.connect(filter).connect(gain).connect(master);source.start()}
  function play(name){if(!started||muted)return;ensure()?.resume();if(name==='select'){tone(310,520,.12,'triangle',.1);tone(620,430,.1,'sine',.06,.07)}else if(name==='cannon'){tone(82,38,.38,'sawtooth',.28);noise(.3,.32,520)}else if(name==='torpedo'){tone(145,48,.52,'sine',.2);noise(.42,.1,260)}else if(name==='harpoon'){tone(780,220,.24,'square',.1);noise(.15,.12,1500)}else if(name==='lightning'){noise(.48,.34,2100);tone(180,48,.42,'sawtooth',.25)}else if(name==='ram'){noise(.38,.2,700);tone(120,62,.3,'triangle',.18)}else if(name==='flare'){tone(420,980,.35,'sine',.13);noise(.18,.08,1800)}else if(name==='hit'){tone(120,54,.22,'square',.16);noise(.18,.2,1200)}else if(name==='shield'){tone(180,760,.48,'sine',.16);tone(260,920,.54,'triangle',.08,.05)}else if(name==='turn'){tone(420,380,.45,'sine',.11);tone(630,560,.4,'sine',.08,.12)}else if(name==='reward'){[440,554,659].forEach((f,i)=>tone(f,f*1.01,.35,'triangle',.09,i*.1))}else if(name==='victory'){[392,494,587,784].forEach((f,i)=>tone(f,f*1.02,.55,'triangle',.12,i*.14))}else if(name==='defeat'){[220,174,130].forEach((f,i)=>tone(f,f*.72,.6,'sawtooth',.1,i*.18))}else if(name==='sail'){noise(.5,.07,340);tone(260,210,.45,'sine',.07)}}
  function setScene(scene){const track=tracks[scene];if(!track)return;currentScene=scene;document.body.dataset.musicScene=scene;if(!started||muted)return;if(currentTrack?.dataset.scene===scene&&!currentTrack.paused)return;currentTrack?.pause();const music=new Audio(track.src);music.dataset.scene=scene;music.loop=track.loop!==false;music.volume=track.volume*preferences.musicVolume/100;currentTrack=music;music.play().catch(()=>{})}
  function start(){started=true;ensure()?.resume();setScene(currentScene);play('sail');updateButton()}
  function setEnabled(enabled){muted=!enabled;preferences.audio=enabled;savePreferences();if(muted)currentTrack?.pause();else setScene(currentScene);refresh();updateButton()}
  function toggle(){setEnabled(muted);return muted}
  function refresh(){if(master)master.gain.value=muted?0:.42*preferences.sfxVolume/100;if(currentTrack)currentTrack.volume=tracks[currentScene].volume*preferences.musicVolume/100}
  function updateButton(){const button=$('#audio-toggle');if(!button)return;button.textContent=muted?'声音 关':'声音 开';button.setAttribute('aria-pressed',String(muted))}
  function stop(){currentTrack?.pause();context?.close();context=null}
  return{start,toggle,setEnabled,refresh,play,setScene,stop}
}
function updateWelcome(hasSave){$('#start-game').textContent=hasSave?'继续航行':'开始航行';$('#new-game').classList.toggle('hidden',!hasSave);$('#welcome-save-copy').textContent=hasSave?`已自动保存 · 第 ${Math.min(state.floor+1,encounters.length)} / ${encounters.length} 站`:'手机请横屏游玩 · 航程会自动保存'}
function newRun(){clearSavedRun();const profile=loadProfile(),level=levelForXp(profile.xp),maxHp=72+(level-1)*4,{seed,route}=makeRoute();state={profile,floor:0,gold:90+(level-1)*15,hero:{hp:maxHp,max:maxHp,block:0},hardware:[],potions:[],enemies:[],deck:['cut','cut','cut','cut','brace','brace','brace','brace','flare','broadside'],draw:[],discard:[],hand:[],energy:3,turn:1,locked:false,battleRewarded:false,lastPotionDrop:null,routeSeed:seed,route,routeHistory:[],currentNode:null,pendingReward:null,pendingNode:null,scene:'map'};keyboardCardIndex=-1;keyboardTargetIndex=-1;clearTimeout(welcomeTimer);welcomeTimer=null;resetEndTurnButton();markCardsSeen(state.deck);$('#overlay').classList.add('hidden');$('#settings-overlay').classList.add('hidden');$('#welcome').classList.remove('departing');$('#start-game').disabled=false;applyPreferences();showMap('title');$('#welcome').classList.remove('hidden');updateWelcome(false);saveRun('map')}
function initializeRun(){const saved=loadSavedRun();if(!saved)return newRun();state=saved;keyboardCardIndex=-1;keyboardTargetIndex=-1;resetEndTurnButton();$('#overlay').classList.add('hidden');$('#settings-overlay').classList.add('hidden');applyPreferences();showMap('title');$('#welcome').classList.remove('hidden');updateWelcome(true)}
function resumeRunScene(){const scene=state.scene||'map',node=routeNode(state.currentNode);if(scene==='battle'&&node){audio.setScene(node.type==='boss'?'boss':node.type==='elite'?'elite':'battle');$('#map-scene').classList.add('hidden');$('#battle-scene').classList.remove('hidden');state.locked=false;render();return}if(scene==='reward'&&state.pendingReward)return showRewards(state.pendingReward.xp,true);if(scene==='event'&&state.pendingNode?.kind==='event')return openSeaEvent(true);if(scene==='treasure'&&state.pendingNode?.kind==='treasure')return openTreasureNode(true);if(scene==='repair'&&state.pendingNode?.kind==='repair')return openRepairNode(true);if(scene==='shipyard'&&state.pendingNode?.kind==='shipyard')return openDrydock();showMap('map')}
function showMap(scene='map'){cancelTarget();audio.setScene(scene);$('#battle-scene').classList.add('hidden');$('#map-scene').classList.remove('hidden');renderHud();renderMap()}
function enterNode(){const node=routeNode(this.dataset.node);if(!node||node.layer!==state.floor)return;audio.play('sail');state.currentNode=node.id;if(!state.routeHistory.includes(node.id))state.routeHistory.push(node.id);state.pendingNode=null;if(node.type==='battle'||node.type==='elite'||node.type==='boss')startBattle(node);else if(node.type==='event')openSeaEvent();else if(node.type==='treasure')openTreasureNode();else if(node.type==='repair')openRepairNode();else if(node.type==='shipyard'){state.pendingNode={kind:'shipyard'};saveRun('shipyard');openDrydock()}}
function startBattle(node=routeNode(state.currentNode)){if(!node)return;const scene=node.type==='boss'?'boss':node.type==='elite'?'elite':'battle';audio.setScene(scene);state.enemies=encounters[node.layer].map(e=>({...e,hp:e.hp,max:e.hp,block:0,move:0,vulnerable:0,sinkShown:false}));state.draw=shuffle([...state.deck]);state.discard=[];state.hand=[];state.turn=1;state.energy=3+(hasHardware('tideCapacitor')?1:0);state.hero.block=hasHardware('foamProjector')?6:0;state.locked=false;state.battleRewarded=false;state.pendingReward=null;keyboardCardIndex=-1;keyboardTargetIndex=-1;draw(5+(hasHardware('deckWinch')?1:0));$('#map-scene').classList.add('hidden');$('#battle-scene').classList.remove('hidden');render();saveRun('battle');if(state.hero.block)showShield($('.hero'));announce('你的回合')}
function shuffle(a){for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
function draw(n){for(let i=0;i<n;i++){if(!state.draw.length){if(!state.discard.length)return;state.draw=shuffle(state.discard);state.discard=[]}if(state.hand.length<8)state.hand.push(state.draw.pop())}}
function play(index,targetIndex=null){
  if(state.locked)return;const id=state.hand[index],c=getCard(id);if(!c||c.cost>state.energy)return announce('潮力不足');
  if(c.type==='attack'){const target=state.enemies[targetIndex];if(!target||target.hp<=0)return;audio.play(c.weapon||'cannon');const enemyEl=document.querySelector(`.enemy-target[data-index="${targetIndex}"]`);animateAttack($('.hero'),enemyEl,'hero',c.weapon||'cannon');let amount=c.damage+(hasHardware('powderMagazine')?2:0);if(target.vulnerable>0)amount=Math.ceil(amount*1.5);deal(target,amount,enemyEl?.querySelector('.portrait'));if(c.vulnerable)target.vulnerable+=c.vulnerable}
  state.energy-=c.cost;if(c.block){audio.play('shield');state.hero.block+=c.block;showShield($('.hero'))}else if(c.type==='skill')audio.play('select');if(c.heal)state.hero.hp=Math.min(state.hero.max,state.hero.hp+c.heal+(hasHardware('copperInfirmary')?2:0));if(c.energy)state.energy+=c.energy;state.hand.splice(index,1);state.discard.push(id);if(c.draw)draw(c.draw);cancelTarget();render();if(state.enemies.every(e=>e.hp<=0))winBattle();else saveRun('battle')
}
function deal(target,amount,element){const absorbed=Math.min(target.block,amount),taken=amount-absorbed;target.block-=absorbed;target.hp=Math.max(0,target.hp-taken);if(taken)audio.play('hit');if(element){const unit=element.closest('.combatant')||element;unit.classList.remove('damage-flash');void unit.offsetWidth;unit.classList.add('damage-flash');spawnNumber(element,taken?`-${taken}`:'格挡',taken>0);spawnSparks(element,taken>0)}}
function spawnNumber(el,text,hurt){const r=el.getBoundingClientRect(),n=document.createElement('div');n.className=`float-number ${hurt?'hurt':'blocked'}`;n.textContent=text;n.style.left=`${r.left+r.width/2}px`;n.style.top=`${r.top+r.height/3}px`;document.body.appendChild(n);setTimeout(()=>n.remove(),850)}
function spawnSparks(el,hurt){if(!hurt)return;const r=el.getBoundingClientRect();for(let i=0;i<7;i++){const s=document.createElement('i');s.className='hit-spark';s.style.left=`${r.left+r.width/2}px`;s.style.top=`${r.top+r.height/2}px`;s.style.setProperty('--sx',`${(Math.random()-.5)*100}px`);s.style.setProperty('--sy',`${-20-Math.random()*70}px`);document.body.appendChild(s);setTimeout(()=>s.remove(),620)}}
function showShield(unit){if(!unit)return;const r=unit.getBoundingClientRect(),s=document.createElement('div');s.className='shield-burst';s.style.left=`${r.left+r.width/2}px`;s.style.top=`${r.top+r.height/2}px`;document.body.appendChild(s);unit.classList.add('bracing');setTimeout(()=>unit.classList.remove('bracing'),500);setTimeout(()=>s.remove(),720)}
function animateAttack(source,target,side,weapon='cannon'){
  if(!source||!target)return;source.classList.add('ship-attacking');const a=source.querySelector('.portrait').getBoundingClientRect(),b=target.querySelector('.portrait').getBoundingClientRect(),startX=a.left+a.width/2,startY=a.top+a.height*.58,endX=b.left+b.width/2,endY=b.top+b.height*.55;
  const launch=(className,delay=0,offset=0)=>{const shot=document.createElement('div');shot.className=`${className} ${side}`;shot.style.left=`${startX}px`;shot.style.top=`${startY+offset}px`;shot.style.setProperty('--dx',`${endX-startX}px`);shot.style.setProperty('--dy',`${endY-startY-offset}px`);shot.style.animationDelay=`${delay}ms`;document.body.appendChild(shot);setTimeout(()=>shot.remove(),760+delay)};
  if(weapon==='lightning'){const bolt=document.createElement('div');bolt.className='lightning-strike';bolt.style.left=`${endX}px`;bolt.style.top=`${Math.max(58,b.top-160)}px`;bolt.style.height=`${Math.min(250,b.top+80)}px`;document.body.appendChild(bolt);setTimeout(()=>bolt.remove(),620)}
  else if(weapon==='broadside'){[-10,0,10].forEach((offset,i)=>launch('cannon-shot broadside-shot',i*75,offset))}
  else if(weapon==='torpedo')launch('torpedo-shot');
  else if(weapon==='harpoon')launch('harpoon-shot');
  else if(weapon==='flare')launch('flare-shot');
  else if(weapon==='ram')launch('ram-wave');
  else launch('cannon-shot');
  setTimeout(()=>source.classList.remove('ship-attacking'),420)
}
function selectPotionTarget(index,button,event){event.stopPropagation();if(state.locked)return;if(selected?.isPotion&&selected.potionIndex===index)return cancelTarget();audio.play('select');cancelTarget();selected={isPotion:true,potionIndex:index,card:button,targetType:'enemy',x:event.clientX,y:event.clientY};button.classList.add('selected');$('#targeting').classList.remove('hidden');document.querySelectorAll('.enemy-target:not(.defeated)').forEach(e=>e.classList.add('target-ready'));window.addEventListener('pointermove',moveTarget);moveTarget(event);$('#hint').textContent='移动箭头并点击一名敌人使用药剂 · Esc 取消'}
function usePotion(index,targetIndex=null){if(state.locked)return;const id=state.potions[index],p=potions[id];if(!p)return;if(p.kind==='heal'){if(state.hero.hp>=state.hero.max)return announce('船体无需修复');state.hero.hp=Math.min(state.hero.max,state.hero.hp+p.value);audio.play('reward')}else if(p.kind==='block'){state.hero.block+=p.value;audio.play('shield');showShield($('.hero'))}else if(p.kind==='energy'){state.energy+=p.value;audio.play('select')}else if(p.kind==='damage'){const target=state.enemies[targetIndex];if(!target||target.hp<=0)return;const enemyEl=document.querySelector(`.enemy-target[data-index="${targetIndex}"]`);audio.play('flare');animateAttack($('.hero'),enemyEl,'hero','flare');deal(target,p.value,enemyEl?.querySelector('.portrait'))}state.potions.splice(index,1);cancelTarget();render();if(state.enemies.every(e=>e.hp<=0))winBattle();else saveRun('battle')}
function potionElement(id,index){const button=document.createElement('button');button.className='potion-slot';if(!id){button.disabled=true;button.innerHTML='<span>空</span>';return button}const p=potions[id];button.title=`${p.name}：${p.text}`;button.innerHTML=`<b>${p.icon}</b><span>${p.name}</span>`;button.onclick=e=>p.target?selectPotionTarget(index,button,e):(e.stopPropagation(),usePotion(index));return button}
function renderPotions(){const belt=$('#potion-belt');if(!belt)return;belt.innerHTML='<span class="potion-label">药剂</span>';for(let i=0;i<3;i++)belt.appendChild(potionElement(state.potions[i],i))}
function resetEndTurnButton(){clearTimeout(endTurnTimer);endTurnTimer=null;endTurnArmed=false;const label=$('#end-turn-label'),copy=$('#end-turn-copy'),button=$('#end-turn');if(label)label.textContent='结束回合';if(copy)copy.textContent='敌人将行动';button?.classList.remove('confirming')}
function requestEndTurn(){if(state.locked)return;if(!preferences.confirmEndTurn||endTurnArmed)return endTurn();endTurnArmed=true;$('#end-turn-label').textContent='再次确认';$('#end-turn-copy').textContent='2 秒内再按一次 E 或点击';$('#end-turn').classList.add('confirming');endTurnTimer=setTimeout(resetEndTurnButton,2000)}
function endTurn(){if(state.locked)return;resetEndTurnButton();audio.play('turn');cancelTarget();state.locked=true;state.discard.push(...state.hand);state.hand=[];render();announce('敌方回合');schedule(()=>runEnemyTurn(0),650)}
function runEnemyTurn(index){while(index<state.enemies.length&&state.enemies[index].hp<=0)index++;if(index>=state.enemies.length)return schedule(beginTurn,550);const enemy=state.enemies[index],m=enemy.moves[enemy.move%enemy.moves.length],enemyEl=document.querySelector(`.enemy-target[data-index="${index}"]`);enemy.block=0;if(m.block){audio.play('shield');enemy.block+=m.block;showShield(enemyEl)}if(m.value){audio.play('cannon');animateAttack(enemyEl,$('.hero'),'enemy');schedule(()=>{deal(state.hero,m.value,$('#hero-portrait'));finishEnemyAction(enemy,index)},230)}else finishEnemyAction(enemy,index)}
function finishEnemyAction(enemy,index){enemy.move++;if(enemy.vulnerable>0)enemy.vulnerable--;render();if(state.hero.hp<=0)return gameOver();schedule(()=>runEnemyTurn(index+1),520)}
function beginTurn(){state.hero.block=0;state.energy=3;state.turn++;state.locked=false;keyboardCardIndex=-1;draw(5);render();saveRun('battle');announce('你的回合')}
function intentText(enemy){const m=enemy.moves[enemy.move%enemy.moves.length];if(m.kind==='block')return `防御 ${m.block}`;if(m.kind==='blockAttack')return `攻击 ${m.value} · 护甲 ${m.block}`;return `攻击 ${m.value}`}
function announce(text){const b=$('#turn-banner');b.firstChild.textContent=text;b.querySelector('small').textContent=`第 ${state.turn} 回合`;b.classList.remove('show');void b.offsetWidth;b.classList.add('show')}
function selectTargetCard(index,card,event,targetType){event.stopPropagation();if(state.locked||getCard(state.hand[index]).cost>state.energy)return announce('潮力不足');if(selected?.index===index)return cancelTarget();audio.play('select');cancelTarget();selected={index,card,targetType,x:event.clientX,y:event.clientY};card.classList.add('selected');const targeting=$('#targeting');targeting.classList.remove('hidden');targeting.classList.toggle('defense',targetType==='hero');if(targetType==='enemy')document.querySelectorAll('.enemy-target:not(.defeated)').forEach(e=>e.classList.add('target-ready'));else $('.hero').classList.add('self-target-ready');window.addEventListener('pointermove',moveTarget);moveTarget(event);$('#hint').textContent=targetType==='enemy'?'移动箭头并点击一名敌人 · Esc 取消':'移动箭头并点击自己的船 · Esc 取消'}
function selectAttack(index,card,event){selectTargetCard(index,card,event,'enemy')}
function selectDefense(index,card,event){selectTargetCard(index,card,event,'hero')}
function moveTarget(event){if(!selected)return;selected.x=event.clientX;selected.y=event.clientY;const r=selected.card.getBoundingClientRect(),sx=r.left+r.width/2,sy=r.top+8,ex=event.clientX,ey=event.clientY,curve=Math.max(55,Math.abs(ex-sx)*.25);$('#target-path').setAttribute('d',`M ${sx} ${sy} C ${sx} ${sy-curve}, ${ex} ${ey+curve}, ${ex} ${ey}`);if(selected.targetType==='enemy')document.querySelectorAll('.enemy-target:not(.defeated)').forEach(enemy=>{const er=enemy.getBoundingClientRect();enemy.classList.toggle('target-hover',ex>=er.left&&ex<=er.right&&ey>=er.top&&ey<=er.bottom)});else{const hero=$('.hero'),hr=hero.getBoundingClientRect();hero.classList.toggle('self-target-hover',ex>=hr.left&&ex<=hr.right&&ey>=hr.top&&ey<=hr.bottom)}}
function chooseTarget(index,event){event.stopPropagation();if(!selected||selected.targetType!=='enemy'||state.enemies[index].hp<=0)return;if(selected.isPotion)usePotion(selected.potionIndex,index);else play(selected.index,index)}
function chooseSelf(event){event.stopPropagation();if(!selected||selected.targetType!=='hero')return;play(selected.index)}
function cancelTarget(){window.removeEventListener('pointermove',moveTarget);selected?.card?.classList.remove('selected');selected=null;keyboardTargetIndex=-1;$('#targeting').classList.add('hidden');$('#targeting').classList.remove('defense');document.querySelectorAll('.enemy-target').forEach(e=>e.classList.remove('target-ready','target-hover','keyboard-target'));$('.hero')?.classList.remove('self-target-ready','self-target-hover','keyboard-target');const hint=$('#hint');if(hint)hint.textContent='攻击牌点敌船 · 防御牌点自己的船 · 1–8 键选牌'}
function winBattle(){if(state.battleRewarded)return;state.battleRewarded=true;state.locked=true;const node=routeNode(state.currentNode),base=[25,30,40,45,55,65,80,120][state.floor]||25,xp=awardXp(node?.type==='elite'?base+15:base);rollPotionDrop();render();schedule(()=>node?.type==='boss'?victory(xp):showRewards(xp),650)}
function rollPotionDrop(){state.lastPotionDrop=null;if(state.floor>=encounters.length-1||state.potions.length>=3)return;if(state.floor===0||Math.random()<.45){const id=shuffle(Object.keys(potions))[0];state.potions.push(id);state.lastPotionDrop=id}}
function awardXp(amount){const before=levelForXp(state.profile.xp);state.profile.xp+=amount;const after=levelForXp(state.profile.xp),levels=after-before;if(levels>0){state.hero.max+=levels*4;state.hero.hp=Math.min(state.hero.max,state.hero.hp+levels*4)}saveProfile();return{amount,leveled:levels>0,level:after}}
function showRewards(xp,restoring=false){
  audio.setScene('reward');audio.play('reward');if(!restoring||!state.pendingReward){const cardId=shuffle(Object.keys(cards).filter(x=>!['cut','brace'].includes(x)))[0],gold=[55,60,85,75,90,100,115][state.floor]||55,available=Object.keys(hardware).filter(id=>!hasHardware(id)),hardwareId=shuffle(available)[0]||'reinforcedHull';state.pendingReward={xp,cardId,gold,hardwareId}}const reward=state.pendingReward;xp=reward.xp;markCardsSeen([reward.cardId]);saveRun('reward');
  const potionCopy=state.lastPotionDrop?` 额外打捞到「${potions[state.lastPotionDrop].name}」，已放入药剂栏。`:'';$('#modal-eyebrow').textContent=`第 ${state.floor+1} 站战斗 · 获得 ${xp.amount} 经验${xp.leveled?` · 升至 ${xp.level} 级`:''}`;$('#modal-title').textContent='只带走一件战利品';$('#modal-copy').textContent=`卡牌扩充战术，金币用于船坞整备，硬件会强化本次航行。${potionCopy}`;const rewards=$('#rewards');rewards.className='rewards mixed-rewards';rewards.innerHTML='';rewards.appendChild(rewardChoice('tactic','',getCard(reward.cardId).name,getCard(reward.cardId).text,'战术卡牌',()=>takeReward(reward.cardId),getCard(reward.cardId).art));rewards.appendChild(rewardChoice('currency','◈',`${reward.gold} 枚金币`,'用于强化或拆解卡牌。','航海物资',()=>takeGold(reward.gold)));rewards.appendChild(rewardChoice('hardware',hardware[reward.hardwareId].icon,hardware[reward.hardwareId].name,hardware[reward.hardwareId].text,'船体硬件',()=>takeHardware(reward.hardwareId)));$('#skip-reward').textContent='放弃战利品';$('#skip-reward').classList.remove('hidden');overlayClose=returnToMap;$('#overlay').classList.remove('hidden')
}
function rewardChoice(type,icon,title,copy,label,onClick,art=''){const button=document.createElement('button');button.className=`reward-choice reward-${type}`;button.innerHTML=`<span class="reward-label">${label}</span><span class="reward-visual">${art?`<img src="${art}" alt="">`:`<b>${icon}</b>`}</span><span class="reward-copy"><strong>${title}</strong><small>${copy}</small></span><span class="reward-select">带走这件</span>`;button.onclick=onClick;return button}
function grantHardware(id){if(!id||hasHardware(id))return false;state.hardware.push(id);if(id==='reinforcedHull'){state.hero.max+=12;state.hero.hp=Math.min(state.hero.max,state.hero.hp+12)}return true}
function addRandomCard(filter=()=>true){const ids=Object.keys(cards).filter(id=>filter(cards[id],id)),id=shuffle(ids)[0];if(!id)return null;state.deck.push(id);markCardsSeen([id]);return id}
function upgradeRandomCards(count=1){const candidates=shuffle(state.deck.map((ref,index)=>parseCard(ref).upgraded?-1:index).filter(index=>index>=0));candidates.slice(0,count).forEach(index=>{const parsed=parseCard(state.deck[index]);state.deck[index]=`${parsed.base}+`});return Math.min(count,candidates.length)}
function addRandomPotion(){if(state.potions.length>=3)return false;state.potions.push(shuffle(Object.keys(potions))[0]);return true}
function takeReward(id){state.deck.push(id);returnToMap()}
function takeGold(amount){state.gold+=amount+(hasHardware('salvageCrane')?20:0);returnToMap()}
function takeHardware(id){grantHardware(id);returnToMap()}
function completeRouteNode(repair=0){state.floor++;state.hero.block=0;if(repair)state.hero.hp=Math.min(state.hero.max,state.hero.hp+repair);state.currentNode=null;state.pendingReward=null;state.pendingNode=null;state.lastPotionDrop=null;$('#overlay').classList.add('hidden');showMap();saveRun('map')}
function returnToMap(){completeRouteNode(12+(hasHardware('repairDrone')?5:0))}
function nodeActionButton(icon,title,copy,onClick,disabled=false){const button=document.createElement('button');button.className='dock-action route-action';button.disabled=disabled;button.innerHTML=`<b>${icon}</b><strong>${title}</strong><span>${copy}</span>`;button.onclick=onClick;return button}
function resolveSeaEvent(choice){if(choice){if(choice.action==='damageGold'){state.hero.hp=Math.max(1,state.hero.hp-choice.damage);state.gold+=choice.gold}else if(choice.action==='card')addRandomCard((card,id)=>!['cut','brace'].includes(id));else if(choice.action==='payHeal'){if(state.gold<choice.cost)return;state.gold-=choice.cost;state.hero.hp=Math.min(state.hero.max,state.hero.hp+choice.heal)}else if(choice.action==='maxHp'){state.hero.max+=choice.max;state.hero.hp=Math.max(1,state.hero.hp-choice.damage)}else if(choice.action==='upgrade')upgradeRandomCards(1);else if(choice.action==='potion'){if(!addRandomPotion())state.gold+=25}else if(choice.action==='hardware'){const id=shuffle(Object.keys(hardware).filter(key=>!hasHardware(key)))[0];if(!grantHardware(id))state.gold+=50}else if(choice.action==='gold')state.gold+=choice.gold;else if(choice.action==='attackCardHeal'){addRandomCard(card=>card.type==='attack');state.hero.hp=Math.min(state.hero.max,state.hero.hp+choice.heal)}else if(choice.action==='goldPotion'){state.gold+=choice.gold;if(!addRandomPotion())state.gold+=20}else if(choice.action==='damageUpgrade'){state.hero.hp=Math.max(1,state.hero.hp-choice.damage);upgradeRandomCards(choice.count)}}audio.play('reward');completeRouteNode()}
function openSeaEvent(restoring=false){audio.setScene('reward');audio.play('select');if(!restoring||state.pendingNode?.kind!=='event'){const event=seaEvents[Math.abs((state.routeSeed+state.floor*17)%seaEvents.length)];state.pendingNode={kind:'event',eventId:event.id}}const event=seaEvents.find(item=>item.id===state.pendingNode.eventId)||seaEvents[0];saveRun('event');$('#modal-eyebrow').textContent='海上事件';$('#modal-title').textContent=event.title;$('#modal-copy').textContent=event.copy;const rewards=$('#rewards');rewards.className='rewards dock-actions node-choices';rewards.innerHTML='';event.choices.forEach((choice,index)=>rewards.appendChild(nodeActionButton(index?'◇':'◆',choice.title,choice.copy,()=>resolveSeaEvent(choice),choice.action==='payHeal'&&state.gold<choice.cost)));$('#skip-reward').textContent='绕开此处';$('#skip-reward').classList.remove('hidden');overlayClose=()=>resolveSeaEvent(null);$('#overlay').classList.remove('hidden')}
function takeTreasure(kind){const treasure=state.pendingNode;if(kind==='card'){state.deck.push(treasure.cardId);markCardsSeen([treasure.cardId])}else if(kind==='hardware'){if(!grantHardware(treasure.hardwareId))state.gold+=70}else state.gold+=treasure.gold;audio.play('reward');completeRouteNode()}
function openTreasureNode(restoring=false){audio.setScene('reward');audio.play('reward');if(!restoring||state.pendingNode?.kind!=='treasure'){const cardId=shuffle(Object.keys(cards).filter(id=>!['cut','brace'].includes(id)))[0],hardwareId=shuffle(Object.keys(hardware).filter(id=>!hasHardware(id)))[0]||null;state.pendingNode={kind:'treasure',cardId,hardwareId,gold:70+state.floor*5}}const treasure=state.pendingNode;saveRun('treasure');$('#modal-eyebrow').textContent='沉船宝藏';$('#modal-title').textContent='只能带走一件货物';$('#modal-copy').textContent='破损货舱正在下沉，选择最适合当前牌组的一件。';const rewards=$('#rewards');rewards.className='rewards mixed-rewards';rewards.innerHTML='';rewards.appendChild(rewardChoice('tactic','',getCard(treasure.cardId).name,getCard(treasure.cardId).text,'沉船卡牌',()=>takeTreasure('card'),getCard(treasure.cardId).art));rewards.appendChild(rewardChoice('currency','◈',`${treasure.gold} 枚金币`,'安全但不会改变战斗方式。','旧船货币',()=>takeTreasure('gold')));if(treasure.hardwareId)rewards.appendChild(rewardChoice('hardware',hardware[treasure.hardwareId].icon,hardware[treasure.hardwareId].name,hardware[treasure.hardwareId].text,'完整硬件',()=>takeTreasure('hardware')));else rewards.appendChild(rewardChoice('currency','◈','额外 70 金币','硬件舱已经被打捞一空。','替代补给',()=>takeTreasure('hardware')));$('#skip-reward').textContent='放弃宝藏';$('#skip-reward').classList.remove('hidden');overlayClose=()=>completeRouteNode();$('#overlay').classList.remove('hidden')}
function resolveRepairNode(action){if(action==='heal')state.hero.hp=Math.min(state.hero.max,state.hero.hp+24);else if(action==='hull'){state.hero.max+=5;state.hero.hp=Math.min(state.hero.max,state.hero.hp+5)}else if(action==='upgrade')upgradeRandomCards(1);audio.play('reward');completeRouteNode()}
function openRepairNode(restoring=false){audio.setScene('reward');audio.play('select');if(!restoring||state.pendingNode?.kind!=='repair')state.pendingNode={kind:'repair'};saveRun('repair');$('#modal-eyebrow').textContent='维修港';$('#modal-title').textContent='潮水只够完成一项工程';$('#modal-copy').textContent='选择修复船体、加固龙骨，或让船匠强化一张卡牌。';const rewards=$('#rewards');rewards.className='rewards dock-actions node-choices repair-choices';rewards.innerHTML='';rewards.appendChild(nodeActionButton('✚','修复船体','恢复 24 点生命',()=>resolveRepairNode('heal'),state.hero.hp>=state.hero.max));rewards.appendChild(nodeActionButton('▰','加固龙骨','最大生命 +5，并恢复 5 点',()=>resolveRepairNode('hull')));rewards.appendChild(nodeActionButton('⬆','打磨战术牌','随机强化一张未强化卡牌',()=>resolveRepairNode('upgrade'),!state.deck.some(ref=>!parseCard(ref).upgraded)));$('#skip-reward').textContent='离开维修港';$('#skip-reward').classList.remove('hidden');overlayClose=()=>completeRouteNode();$('#overlay').classList.remove('hidden')}
function closeDrydock(){if(state.pendingNode?.kind==='shipyard')return completeRouteNode();$('#overlay').classList.add('hidden');audio.setScene('map');renderHud()}
function openDrydock(){audio.setScene('reward');audio.play('select');if(state.pendingNode?.kind==='shipyard')saveRun('shipyard');const list=state.hardware.length?state.hardware.map(id=>hardware[id].name).join(' · '):'尚未安装硬件';$('#modal-eyebrow').textContent=state.pendingNode?.kind==='shipyard'?'航线船坞':'航线整备';$('#modal-title').textContent='整备甲板';$('#modal-copy').textContent=`持有 ${state.gold} 金币 · ${list}`;const rewards=$('#rewards');rewards.className='rewards dock-actions';rewards.innerHTML='<button class="dock-action" data-mode="upgrade"><b>⬆</b><strong>强化卡牌</strong><span>75 金币 · 提升伤害、护甲或修复量</span></button><button class="dock-action danger" data-mode="remove"><b>✂</b><strong>拆解卡牌</strong><span>55 金币 · 精简牌组，提高抽牌稳定性</span></button>';rewards.querySelectorAll('.dock-action').forEach(button=>button.onclick=()=>showDeckOperation(button.dataset.mode));$('#skip-reward').textContent=state.pendingNode?.kind==='shipyard'?'离开船坞':'返回航线';$('#skip-reward').classList.remove('hidden');overlayClose=closeDrydock;$('#overlay').classList.remove('hidden')}
function showDeckOperation(mode){const upgrade=mode==='upgrade',cost=upgrade?75:55;$('#modal-title').textContent=upgrade?'选择要预览的卡牌':'选择要检查的卡牌';$('#modal-copy').textContent=`先查看${upgrade?'强化前后效果':'拆解确认'}，确认后才会扣除 ${cost} 金币。`;const rewards=$('#rewards');rewards.className='rewards deck-picker';rewards.innerHTML='';state.deck.forEach((ref,index)=>{const card=cardElement(ref,null,true,()=>openDeckConfirmation(mode,index));if(upgrade&&parseCard(ref).upgraded){card.disabled=true;card.classList.add('unplayable')}rewards.appendChild(card)});$('#skip-reward').textContent='返回整备';$('#skip-reward').classList.remove('hidden');overlayClose=openDrydock}
function previewCard(ref,label){const wrap=document.createElement('div'),card=cardElement(ref,null,true,()=>{});wrap.className='preview-card-wrap';wrap.innerHTML=`<span>${label}</span>`;card.classList.add('preview-card');card.onclick=null;card.tabIndex=-1;wrap.appendChild(card);return wrap}
function openDeckConfirmation(mode,index){const ref=state.deck[index],upgrade=mode==='upgrade',cost=upgrade?75:55,rewards=$('#rewards');if(!ref)return showDeckOperation(mode);$('#modal-title').textContent=upgrade?'预览强化效果':'确认拆解卡牌';$('#modal-copy').textContent=upgrade?'数值变化会在右侧高亮显示。只有点击确认才会扣费。':'拆解后这张卡会从本次航行的牌组中永久移除。';rewards.className=`rewards deck-confirm ${upgrade?'upgrade-confirm':'remove-confirm'}`;rewards.innerHTML='';if(upgrade){const parsed=parseCard(ref);rewards.appendChild(previewCard(ref,'强化前'));const arrow=document.createElement('div');arrow.className='upgrade-arrow';arrow.textContent='→';rewards.appendChild(arrow);rewards.appendChild(previewCard(`${parsed.base}+`,'强化后'))}else{rewards.appendChild(previewCard(ref,'将被拆解'));const warning=document.createElement('div');warning.className='remove-warning';warning.innerHTML='<b>拆解不可撤销</b><span>确认后它会立即离开当前牌组。</span>';rewards.appendChild(warning)}const confirm=document.createElement('button'),blocked=state.gold<cost||(mode==='remove'&&state.deck.length<=6);confirm.className=`confirm-deck-action ${upgrade?'':'danger'}`;confirm.textContent=blocked?(state.gold<cost?`金币不足（需要 ${cost}）`:'牌组至少保留 6 张'):`确认${upgrade?'强化':'拆解'} · ${cost} 金币`;confirm.disabled=blocked;confirm.onclick=()=>confirmDeckOperation(mode,index);rewards.appendChild(confirm);$('#skip-reward').textContent='返回选牌';$('#skip-reward').classList.remove('hidden');overlayClose=()=>showDeckOperation(mode)}
function confirmDeckOperation(mode,index){const cost=mode==='upgrade'?75:55,ref=state.deck[index];if(!ref||state.gold<cost||mode==='remove'&&state.deck.length<=6)return;if(mode==='upgrade'){const parsed=parseCard(ref);if(parsed.upgraded)return;state.deck[index]=`${parsed.base}+`}else state.deck.splice(index,1);state.gold-=cost;audio.play('reward');renderHud();if(state.pendingNode?.kind==='shipyard')saveRun('shipyard');openDrydock()}
function openCardLibrary(){audio.setScene('reward');audio.play('select');const ids=Object.keys(cards),seen=new Set(state.profile.seenCards),rewards=$('#rewards');$('#modal-eyebrow').textContent='航海牌典';$('#modal-title').textContent=`已发现 ${ids.filter(id=>seen.has(id)).length} / ${ids.length}`;$('#modal-copy').textContent='这里记录全部战术卡、当前持有数量与战斗词条。';rewards.className='rewards card-library';rewards.innerHTML=combatGlossaryMarkup();ids.forEach((id,index)=>rewards.appendChild(libraryEntry(id,index,seen.has(id))));$('#skip-reward').textContent='返回航线';$('#skip-reward').classList.remove('hidden');overlayClose=closeDrydock;$('#overlay').classList.remove('hidden')}
function libraryEntry(id,index,seen){const entry=document.createElement('article'),owned=state.deck.filter(ref=>parseCard(ref).base===id),upgraded=owned.filter(ref=>parseCard(ref).upgraded).length,c=cards[id];entry.className=`library-entry ${seen?'discovered':'undiscovered'}`;entry.innerHTML=`<span class="library-index">航图 ${String(index+1).padStart(2,'0')}</span><div class="library-art">${seen?`<img src="${c.art}" alt="">`:'?'}</div><h3>${seen?c.name:'尚未发现'}</h3><p>${seen?c.text:'在远航中遇见它后，效果会记录在这里。'}</p><footer>${seen?`当前持有 ${owned.length}${upgraded?` · 已强化 ${upgraded}`:''}`:'未收录'}</footer>`;if(seen){const help=cardRuleHelp(c);if(help)entry.title=help}return entry}
function settingsRow(title,copy,control){return`<div class="setting-row"><div><strong>${title}</strong><small>${copy}</small></div>${control}</div>`}
function settingsToggle(key,title,copy){return settingsRow(title,copy,`<button class="setting-toggle ${preferences[key]?'on':''}" data-setting="${key}" aria-pressed="${preferences[key]}"><span></span>${preferences[key]?'开启':'关闭'}</button>`)}
function musicCreditsMarkup(){return`<div class="music-credits"><p>本版配乐鸣谢</p>${musicCredits.map(([scene,title,artist,license,url])=>`<a href="${url}" target="_blank" rel="noopener"><span>${scene}</span><b>${title}</b><small>${artist} · ${license}</small></a>`).join('')}</div>`}
function renderSettingsTab(tab=settingsTab){settingsTab=tab;document.querySelectorAll('[data-settings-tab]').forEach(button=>button.classList.toggle('active',button.dataset.settingsTab===tab));const content=$('#settings-content');if(tab==='game'){content.innerHTML=`<div class="setting-group"><p>航行规则</p>${settingsRow('语言','当前试玩版使用简体中文。','<b class="setting-value">简体中文</b>')}${settingsToggle('screenShake','屏幕抖动','船只受击时产生轻微冲击反馈。')}${settingsToggle('fastMode','加速模式','缩短敌方行动与战后结算等待。')}${settingsToggle('pileCounts','显示牌堆计数','在战斗底部显示抽牌堆和弃牌堆数量。')}${settingsToggle('confirmEndTurn','结束回合确认','开启后需要二次点击或再按一次 E。')}</div>`}else if(tab==='video'){content.innerHTML=`<div class="setting-group"><p>画面表现</p>${settingsToggle('reducedEffects','精简战斗特效','减少火花、闪光和持续动画，适合性能较弱的手机。')}${settingsRow('界面缩放','自动适应电脑与手机横屏。','<b class="setting-value">自适应</b>')}${settingsRow('显示方向','手机端保持横屏可完整显示战场。','<b class="setting-value">横屏</b>')}${settingsRow('全屏航行','让浏览器进入或退出全屏。','<button class="setting-action" data-settings-action="fullscreen">切换全屏</button>')}</div>`}else if(tab==='audio'){content.innerHTML=`<div class="setting-group"><p>声音</p>${settingsToggle('audio','总声音','同时开启或关闭配乐与战斗音效。')}${settingsRow('配乐音量','标题、地图、普通战斗、精英战、首领战和奖励配乐。',`<label class="volume-control"><input type="range" min="0" max="100" step="10" value="${preferences.musicVolume}" data-volume="musicVolume"><output>${preferences.musicVolume}%</output></label>`)}${settingsRow('音效音量','炮击、护甲、受击和奖励音效。',`<label class="volume-control"><input type="range" min="0" max="100" step="10" value="${preferences.sfxVolume}" data-volume="sfxVolume"><output>${preferences.sfxVolume}%</output></label>`)}</div>${musicCreditsMarkup()}`}else{const controls=[['确认选牌 / 使用目标','Enter'],['取消选牌 / 打开或关闭设置','Esc'],['查看航线地图','M'],['查看当前牌组','D'],['查看抽牌堆','A'],['查看弃牌堆','S'],['查看消耗牌堆','X'],['结束回合','E'],['查看船只状态','Space'],['切换手牌','← / →'],['切换目标','↑ / ↓'],['选择第 1–8 张牌','1–8']];content.innerHTML=`<div class="setting-group controls-group"><p>键盘操作</p><div class="controls-head"><span>操作指令</span><span>按键</span></div>${controls.map(([name,key])=>`<div class="control-row"><span>${name}</span><kbd>${key}</kbd></div>`).join('')}<small class="controller-note">浏览器版同时保留鼠标与触屏操作；键盘快捷键可在战斗中直接使用。</small></div>`}content.querySelectorAll('[data-setting]').forEach(button=>button.onclick=()=>togglePreference(button.dataset.setting));content.querySelectorAll('[data-volume]').forEach(input=>input.oninput=()=>{preferences[input.dataset.volume]=Number(input.value);input.nextElementSibling.textContent=`${input.value}%`;savePreferences();audio.refresh()});content.querySelector('[data-settings-action="fullscreen"]')?.addEventListener('click',()=>document.fullscreenElement?document.exitFullscreen?.():document.documentElement.requestFullscreen?.())}
function togglePreference(key){if(key==='audio')audio.setEnabled(!preferences.audio);else{preferences[key]=!preferences[key];savePreferences();if(key==='confirmEndTurn'&&!preferences[key])resetEndTurnButton();applyPreferences()}renderSettingsTab(settingsTab)}
function openSettings(){cancelTarget();audio.play('select');renderSettingsTab(settingsTab);$('#settings-overlay').classList.remove('hidden');document.querySelector(`[data-settings-tab="${settingsTab}"]`)?.focus()}
function closeSettings(){$('#settings-overlay').classList.add('hidden');$('#settings-button').focus()}
function resetSettings(){preferences={...settingDefaults};savePreferences();audio.setEnabled(preferences.audio);applyPreferences();resetEndTurnButton();renderSettingsTab(settingsTab)}
function openInfo(title,copy,className){if(!$('#overlay').classList.contains('hidden'))return false;audio.play('select');$('#overlay').dataset.kind='info';$('#modal-eyebrow').textContent='航行资料';$('#modal-title').textContent=title;$('#modal-copy').textContent=copy;const rewards=$('#rewards');rewards.className=`rewards info-panel ${className}`;rewards.innerHTML='';$('#skip-reward').textContent='返回航行';$('#skip-reward').classList.remove('hidden');overlayClose=closeInfo;$('#overlay').classList.remove('hidden');return true}
function closeInfo(){delete $('#overlay').dataset.kind;$('#overlay').classList.add('hidden')}
function openDeckViewer(title,refs,emptyCopy='这里暂时没有卡牌。'){if(!openInfo(title,`共 ${refs.length} 张 · 这里只查看，不会改变牌组。`,'deck-picker info-deck'))return;const rewards=$('#rewards');if(!refs.length){rewards.innerHTML=`<div class="empty-pile"><b>∅</b><span>${emptyCopy}</span></div>`;return}refs.forEach(ref=>{const card=cardElement(ref,null,true,()=>{});card.classList.add('info-card');card.onclick=null;card.tabIndex=-1;rewards.appendChild(card)})}
function openRouteViewer(){if(!openInfo('航线进度',`当前位于第 ${Math.min(state.floor+1,encounters.length)} / ${encounters.length} 站。`,'route-info'))return;const history=new Set(state.routeHistory);$('#rewards').innerHTML=state.route.map((layer,index)=>{const chosen=layer.find(node=>history.has(node.id)),name=chosen?.name||(index===state.floor?'分叉待选':'未抵达');return`<div class="route-step ${index<state.floor?'cleared':index===state.floor?'current':'locked'}"><b>${index+1}</b><span>${name}</span><small>${index<state.floor?'已完成':index===state.floor?'选择航线':'未抵达'}</small></div>`}).join('')}
function openStatusViewer(){if(!openInfo('船只状态','当前回合与长期成长一览。','status-sheet'))return;const level=levelForXp(state.profile.xp),hardwareNames=state.hardware.map(id=>hardware[id].name).join(' · ')||'尚未安装长期硬件';$('#rewards').innerHTML=`<div class="status-meters"><div><small>船体</small><b>${state.hero.hp} / ${state.hero.max}</b></div><div><small>护甲</small><b>${state.hero.block}</b></div><div><small>潮力</small><b>${state.energy}</b></div><div><small>船长等级</small><b>${level}</b></div><div><small>牌组</small><b>${state.deck.length} 张</b></div><div><small>药剂</small><b>${state.potions.length} / 3</b></div></div><p class="status-hardware"><b>长期硬件</b><span>${hardwareNames}</span></p>`}
function battleVisible(){return!$('#battle-scene').classList.contains('hidden')}
function focusHandCard(index){if(!battleVisible()||state.locked||!state.hand.length)return;keyboardCardIndex=(index%state.hand.length+state.hand.length)%state.hand.length;document.querySelectorAll('#hand .card').forEach(card=>card.classList.remove('keyboard-focus'));const card=$('#hand').children[keyboardCardIndex];card?.classList.add('keyboard-focus');card?.focus({preventScroll:true})}
function cycleKeyboardTarget(step,initial=false){if(!selected)return;document.querySelectorAll('.keyboard-target').forEach(el=>el.classList.remove('keyboard-target'));if(selected.targetType==='hero'){keyboardTargetIndex=0;const hero=$('.hero'),r=hero.getBoundingClientRect();hero.classList.add('keyboard-target');moveTarget({clientX:r.left+r.width/2,clientY:r.top+r.height/2});return}const living=state.enemies.map((enemy,index)=>enemy.hp>0?index:-1).filter(index=>index>=0);if(!living.length)return;let position=living.indexOf(keyboardTargetIndex);position=initial||position<0?(step<0?living.length-1:0):(position+step+living.length)%living.length;keyboardTargetIndex=living[position];const target=document.querySelector(`.enemy-target[data-index="${keyboardTargetIndex}"]`),r=target.getBoundingClientRect();target.classList.add('keyboard-target');moveTarget({clientX:r.left+r.width/2,clientY:r.top+r.height/2})}
function activateKeyboardCard(index){const card=$('#hand').children[index],ref=state.hand[index];if(!card||!ref)return;const c=getCard(ref),r=card.getBoundingClientRect(),event={stopPropagation(){},clientX:r.left+r.width/2,clientY:r.top};keyboardCardIndex=index;if(c.type==='attack')selectAttack(index,card,event);else if(c.block)selectDefense(index,card,event);else play(index);if(selected)cycleKeyboardTarget(1,true)}
function confirmKeyboard(){if(selected){if(selected.targetType==='hero')chooseSelf({stopPropagation(){}});else if(keyboardTargetIndex>=0)chooseTarget(keyboardTargetIndex,{stopPropagation(){}});return}if(keyboardCardIndex<0)focusHandCard(0);else activateKeyboardCard(keyboardCardIndex)}
function startGame(){if(welcomeTimer)return;audio.start();$('#welcome').classList.add('departing');$('#start-game').disabled=true;welcomeTimer=setTimeout(()=>{$('#welcome').classList.add('hidden');$('#welcome').classList.remove('departing');$('#start-game').disabled=false;resumeRunScene();welcomeTimer=null},gameDelay(1400))}
function handleKeyboard(event){if(event.ctrlKey||event.metaKey||event.altKey)return;const key=event.key,settingsOpen=!$('#settings-overlay').classList.contains('hidden'),welcomeOpen=!$('#welcome').classList.contains('hidden'),overlayOpen=!$('#overlay').classList.contains('hidden');if(settingsOpen){if(key==='Escape'){event.preventDefault();closeSettings()}return}if(welcomeOpen){if(key==='Enter'){event.preventDefault();startGame()}return}if(overlayOpen){if(key==='Escape'&&$('#overlay').dataset.kind==='info'){event.preventDefault();closeInfo()}return}if((key==='Enter'||key===' ')&&event.target.closest?.('button,input')&&!event.target.closest('#hand'))return;if(key==='Escape'){event.preventDefault();if(selected)cancelTarget();else openSettings();return}if(key.toLowerCase()==='d'){event.preventDefault();openDeckViewer(`当前牌组 · ${state.deck.length} 张`,state.deck);return}if(key.toLowerCase()==='a'){event.preventDefault();openDeckViewer(`抽牌堆 · ${state.draw.length} 张`,state.draw);return}if(key.toLowerCase()==='s'){event.preventDefault();openDeckViewer(`弃牌堆 · ${state.discard.length} 张`,state.discard);return}if(key.toLowerCase()==='x'){event.preventDefault();openDeckViewer('消耗牌堆 · 0 张',[],'当前版本尚无消耗牌，加入消耗机制后会显示在这里。');return}if(key.toLowerCase()==='m'){event.preventDefault();if(battleVisible())openRouteViewer();return}if(key===' '){event.preventDefault();openStatusViewer();return}if(!battleVisible()){if(key==='Enter'){event.preventDefault();document.querySelector('.chart-node.current')?.click()}return}if(key.toLowerCase()==='e'){event.preventDefault();requestEndTurn();return}if(/^[1-8]$/.test(key)){event.preventDefault();const index=Number(key)-1;if(index<state.hand.length){focusHandCard(index);activateKeyboardCard(index)}return}if(key==='ArrowLeft'||key==='ArrowRight'){event.preventDefault();if(selected)cancelTarget();focusHandCard((keyboardCardIndex<0?0:keyboardCardIndex)+(key==='ArrowLeft'?-1:1));return}if(key==='ArrowUp'||key==='ArrowDown'){event.preventDefault();if(selected)cycleKeyboardTarget(key==='ArrowUp'?-1:1);else focusHandCard(keyboardCardIndex<0?0:keyboardCardIndex);return}if(key==='Enter'){event.preventDefault();confirmKeyboard()}}
function gameOver(){clearSavedRun();audio.play('defeat');showEnd('航线中断','你的船沉入了无光海。下一次航行会保留你的经验。','再次启航')}
function victory(xp){clearSavedRun();audio.play('victory');showEnd('你穿过了风暴',`塔心的灯重新亮起。本场获得 ${xp.amount} 经验，船长等级 ${levelForXp(state.profile.xp)}。`,'开始新航程')}
function showEnd(title,copy,button){$('#modal-eyebrow').textContent='航程记录';$('#modal-title').textContent=title;$('#modal-copy').textContent=copy;$('#rewards').className='rewards';$('#rewards').innerHTML=`<button class="primary-button" id="again">${button}</button>`;$('#skip-reward').classList.add('hidden');$('#overlay').classList.remove('hidden');$('#again').onclick=newRun}
function cardElement(id,index,reward=false,onSelect=null){const c=getCard(id),upgraded=parseCard(id).upgraded,inHand=Number.isInteger(index),b=document.createElement('button'),help=cardRuleHelp(c);b.className=`card ${c.type}${upgraded?' upgraded':''}${inHand?' in-hand':''}${!reward&&c.cost>state.energy?' unplayable':''}`;b.innerHTML=`<span class="card-cost">${c.cost}</span>${inHand?`<span class="card-hotkey">${index+1}</span>`:''}${upgraded?'<span class="upgrade-mark">+</span>':''}<div class="card-art"><img src="${c.art}" alt=""></div><h3>${c.name}</h3><p>${c.text}</p><span class="card-type">${c.type==='attack'?'攻击':'技能'}</span>`;b.setAttribute('aria-label',`${c.name}，消耗 ${c.cost} 点潮力。${c.text}${help?` ${help.replace(/\n/g,' ')}`:''}`);if(help)b.title=help;if(onSelect)b.onclick=onSelect;else if(reward)b.onclick=()=>takeReward(id);else if(c.type==='attack')b.onclick=e=>selectAttack(index,b,e);else if(c.block)b.onclick=e=>selectDefense(index,b,e);else b.onclick=e=>{e.stopPropagation();play(index)};return b}
function enemyElement(enemy,index){const el=document.createElement('article'),src=enemy.sprite==='boss'?'assets/boss-ship-v1.png':'assets/raider-ship-v1.png',defeatClass=enemy.hp<=0?(enemy.sinkShown?' defeated sunk':' defeated sinking'):'';el.className=`combatant enemy enemy-target ship-${enemy.sprite}${enemy.block?' has-block':''}${defeatClass}`;el.dataset.index=index;el.style.setProperty('--variant',enemy.variant||0);el.innerHTML=`<div class="intent"><small>下一步</small><strong>${enemy.hp>0?intentText(enemy):'已击败'}</strong></div><div class="portrait enemy-portrait"><img class="ship-sprite" src="${src}" alt="${enemy.name}"></div><div class="nameplate"><strong>${enemy.name}</strong><small>${enemy.title}</small></div><div class="health"><div style="width:${enemy.hp/enemy.max*100}%"></div><span>${enemy.hp} / ${enemy.max}</span></div><div class="status-row"><span class="status ${enemy.block?'':'hidden'}">护甲 ${enemy.block}</span>${enemy.vulnerable?`<span class="status status-rust" title="${combatTerms.rust.text}">锈蚀 ${enemy.vulnerable} · +50%</span>`:''}</div>`;el.onclick=e=>chooseTarget(index,e);return el}
function hardwareRelic(id){const item=hardware[id],button=document.createElement('button');button.className='hardware-relic';button.type='button';button.setAttribute('aria-label',`${item.name}：${item.text}`);button.setAttribute('aria-expanded','false');button.innerHTML=`<span class="relic-icon">${item.icon}</span><span class="relic-tooltip" role="tooltip"><small>长期硬件 · 本次航行持续生效</small><strong>${item.name}</strong><span>${item.text}</span></span>`;button.onclick=e=>{e.stopPropagation();const opening=!button.classList.contains('active');document.querySelectorAll('.hardware-relic.active').forEach(el=>{el.classList.remove('active');el.setAttribute('aria-expanded','false')});button.classList.toggle('active',opening);button.setAttribute('aria-expanded',String(opening))};return button}
function renderHardware(){const shelf=$('#relic-shelf'),key=state.hardware.join('|');if(!shelf||shelf.dataset.items===key)return;shelf.dataset.items=key;shelf.innerHTML='';shelf.classList.toggle('hidden',!state.hardware.length);if(!state.hardware.length)return;const label=document.createElement('span');label.className='relic-shelf-label';label.textContent='长期硬件';shelf.appendChild(label);state.hardware.forEach(id=>shelf.appendChild(hardwareRelic(id)))}
function renderHud(){const level=levelForXp(state.profile.xp);$('#hud-hp').textContent=`${state.hero.hp} / ${state.hero.max}`;$('#hud-gold').textContent=state.gold;$('#hud-level').textContent=level;$('#hud-xp').textContent=xpProgress();$('#floor').textContent=`${Math.min(state.floor+1,encounters.length)} / ${encounters.length}`;$('#deck-count').textContent=state.deck.length;$('#hardware-count').textContent=state.hardware.length;$('#potion-count').textContent=`${state.potions.length} / 3`;renderHardware()}
function renderMap(){const history=new Set(state.routeHistory),nodes=$('#chart-nodes'),lines=$('#route-lines'),last=routeNode(state.routeHistory[state.routeHistory.length-1]),pos=last||{x:1,y:50};nodes.innerHTML='';routeNodes().forEach(node=>{const definition=routeTypes[node.type],button=document.createElement('button'),past=node.layer<state.floor,chosen=history.has(node.id),current=node.layer===state.floor;button.className=`chart-node route-${node.type}${node.type==='elite'?' elite':''}${node.type==='boss'?' boss':''}${chosen?' cleared':past?' passed':current?' current':' locked'}`;button.dataset.node=node.id;button.style.setProperty('--x',`${node.x}%`);button.style.setProperty('--y',`${node.y}%`);button.disabled=!current;button.innerHTML=`<i>${definition.icon}</i><b>${node.name}</b><small>${definition.label}</small>`;button.onclick=enterNode;nodes.appendChild(button)});const edge=(a,b,status)=>{const ax=a.x*8,ay=a.y*4.1,bx=b.x*8,by=b.y*4.1,mx=(ax+bx)/2;return`<path class="route-path ${status}" d="M ${ax} ${ay} C ${mx} ${ay}, ${mx} ${by}, ${bx} ${by}"/>`},paths=[];const start={id:'start',layer:-1,x:0,y:50};state.route[0].forEach(node=>paths.push(edge(start,node,state.floor===0?'available':'passed')));for(let layer=0;layer<state.route.length-1;layer++)state.route[layer].forEach(from=>state.route[layer+1].forEach(to=>{const selected=history.has(from.id)&&history.has(to.id),available=history.has(from.id)&&to.layer===state.floor;paths.push(edge(from,to,selected?'cleared':available?'available':to.layer<state.floor?'passed':'locked'))}));lines.innerHTML=paths.join('');$('#map-ship-token').style.setProperty('--ship-x',`${pos.x}%`);$('#map-ship-token').style.setProperty('--ship-y',`${pos.y}%`);$('#map-guidance').textContent=state.floor===encounters.length-1?'风暴中心就在前方。两条航线已经汇入首领海域。':'每一层选择一条航线；事件、宝藏和船坞不会触发战斗'}
function render(){renderHud();renderPotions();const h=state.hero;$('.hero').classList.toggle('has-block',h.block>0);$('#hero-health').textContent=`${h.hp} / ${h.max}`;$('#hero-health-bar').style.width=`${h.hp/h.max*100}%`;$('#hero-block').textContent=`护甲 ${h.block}`;$('#hero-block').classList.toggle('hidden',!h.block);$('#energy').textContent=state.energy;$('#draw-count').textContent=state.draw.length;$('#discard-count').textContent=state.discard.length;const enemies=$('#enemies');enemies.className=`enemies enemies-${state.enemies.length}`;enemies.innerHTML='';state.enemies.forEach((enemy,i)=>{const wasNewSink=enemy.hp<=0&&!enemy.sinkShown;enemies.appendChild(enemyElement(enemy,i));if(wasNewSink)enemy.sinkShown=true});$('#hand').innerHTML='';const mid=(state.hand.length-1)/2;state.hand.forEach((id,i)=>{const card=cardElement(id,i),offset=i-mid;card.style.setProperty('--rot',`${offset*3.5}deg`);card.style.setProperty('--fan-y',`${Math.abs(offset)*4}px`);card.style.zIndex=i+1;$('#hand').appendChild(card)});if(keyboardCardIndex>=state.hand.length)keyboardCardIndex=state.hand.length-1;if(keyboardCardIndex>=0)$('#hand').children[keyboardCardIndex]?.classList.add('keyboard-focus');$('#end-turn').disabled=state.locked}
document.querySelectorAll('[data-settings-tab]').forEach(button=>button.onclick=()=>renderSettingsTab(button.dataset.settingsTab));document.addEventListener('click',e=>{document.querySelectorAll('.hardware-relic.active').forEach(el=>{el.classList.remove('active');el.setAttribute('aria-expanded','false')});if(selected&&!e.target.closest('.card')&&!e.target.closest('.potion-slot')&&!e.target.closest('.enemy-target')&&!e.target.closest('.hero'))cancelTarget()});document.addEventListener('keydown',handleKeyboard);$('.hero').onclick=chooseSelf;$('#start-game').onclick=startGame;$('#new-game').onclick=newRun;$('#settings-button').onclick=openSettings;$('#close-settings').onclick=closeSettings;$('#settings-overlay').onclick=e=>{if(e.target===$('#settings-overlay'))closeSettings()};$('#reset-settings').onclick=resetSettings;$('#audio-toggle').onclick=()=>audio.toggle();$('#library-button').onclick=openCardLibrary;$('#end-turn').onclick=requestEndTurn;$('#restart').onclick=newRun;$('#skip-reward').onclick=()=>overlayClose();globalThis.addEventListener('pagehide',()=>audio.stop(),{once:true});initializeRun();
